mapper.insert:
INSERT INTO ATTENDANCE ( ATT_ID, EMP_ID, ATT_STTS, ATT_CHECK_IN, ATT_WORK_DT, ATT_LATE_YN ) VALUES ( SEQ_ATT_ID.NEXTVAL, #{empId}, '출근', (SELECT CASE WHEN S.ATT_WORK_STTS = '오전반차' THEN TO_DATE(TO_CHAR(SYSDATE, 'YYYY-MM-DD') || ' 09:00:00', 'YYYY-MM-DD HH24:MI:SS') /* 🎯 이제 + 9/24는 삭제! SYSDATE가 이미 한국 시간이면 그대로 사용 */ ELSE SYSDATE END FROM ATTENDANCE_WORK_STATUS S WHERE S.EMP_ID = #{empId}),
/* 🎯 날짜도 보정 없이 오늘 날짜 그대로! */ TRUNC(SYSDATE),
(SELECT CASE WHEN S.ATT_WORK_STTS = '오전반차' THEN 'N' /* 🎯 09:05 기준 지각 체크 */ WHEN TO_CHAR(SYSDATE, 'HH24MI') > '0905' THEN 'Y' ELSE 'N' END FROM ATTENDANCE_WORK_STATUS S WHERE S.EMP_ID = #{empId}) )

mapper.update:
UPDATE EMPLOYEE
SET
EMP_MLG = EMP_MLG + #{empMlg}
WHERE EMP_ID = #{empId}

UPDATE APRV_VCT_DOC
SET VCT_STTS = '신청중'
WHERE ATT_TYPE_ID = #{attTypeId}
AND EMP_ID = #{empId}

UPDATE APRV_BZTRP_DOC
SET BZTRP_STTS = '신청중'
WHERE ATT_TYPE_ID = #{attTypeId}
AND EMP_ID = #{empId}

UPDATE APRV_EXCS_WORK_DOC
SET EXCS_WORK_STTS = '신청중'
WHERE ATT_TYPE_ID = #{attTypeId}
AND EMP_ID = #{empId}

UPDATE ANNUAL_LEAVE
SET
ANN_LEAVE_USED = ANN_LEAVE_USED + (
SELECT VCT_TOTAL_DAYS
FROM APRV_VCT_DOC
WHERE ATT_TYPE_ID = #{attTypeId}
),
ANN_LEAVE_REMAIN = ANN_LEAVE_REMAIN - (
SELECT VCT_TOTAL_DAYS
FROM APRV_VCT_DOC
WHERE ATT_TYPE_ID = #{attTypeId}
)
WHERE
EMP_ID = #{empId}
AND ANN_LEAVE_YEAR = TO_CHAR(SYSDATE, 'YYYY')
AND EXISTS (
SELECT 1
FROM APRV_VCT_DOC
WHERE ATT_TYPE_ID = #{attTypeId}
AND VCT_STTS = '신청중'
)

UPDATE ATTENDANCE_WORK_STATUS
SET ATT_WORK_STTS = #{attStts}
WHERE EMP_ID = #{empId}
